function decodeXml(value) {
  return value
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

function stripCdata(value) {
  return value.replace(/^<!\[CDATA\[/, '').replace(/\]\]>$/, '');
}

function getTag(entry, tagName) {
  const match = entry.match(new RegExp(`<${tagName}[^>]*>([\\s\\S]*?)</${tagName}>`));
  return match ? decodeXml(stripCdata(match[1].trim())) : '';
}

function getAlternateLink(entry) {
  const match = entry.match(/<link\b[^>]*rel=["']alternate["'][^>]*href=["']([^"']+)["'][^>]*\/?>/);
  return match ? decodeXml(match[1]) : '';
}

const feed = $input.first().json.data;
const entries = [...feed.matchAll(/<entry>([\s\S]*?)<\/entry>/g)]
  .map((match) => match[1])
  .map((entry) => {
    const title = getTag(entry, 'title');
    const videoId = getTag(entry, 'yt:videoId');
    const published = getTag(entry, 'published');
    const updated = getTag(entry, 'updated');
    const link = videoId ? `https://www.youtube.com/watch?v=${videoId}` : getAlternateLink(entry);
    return { title, videoId, link, published, updated };
  })
  .filter((entry) => entry.title && entry.videoId && entry.link)
  .sort((a, b) => new Date(b.published || b.updated) - new Date(a.published || a.updated));

if (entries.length === 0) {
  return [];
}

const state = $getWorkflowStaticData('global');
state.seenVideoIds ||= [];

const seen = new Set(state.seenVideoIds);
const unseen = entries.filter((entry) => !seen.has(entry.videoId));

if (!state.initialized) {
  state.seenVideoIds = entries.slice(0, 30).map((entry) => entry.videoId);
  state.initialized = true;
  state.initializedAt = new Date().toISOString();
  return [];
}

if (unseen.length === 0) {
  return [];
}

const selected = unseen[0];
state.seenVideoIds = [...new Set([selected.videoId, ...state.seenVideoIds])].slice(0, 100);
state.lastPublishedVideoId = selected.videoId;
state.lastPublishedAt = new Date().toISOString();

return [
  {
    json: {
      title: selected.title,
      link: selected.link,
      videoId: selected.videoId,
      published: selected.published,
      value1: selected.title,
      value2: selected.link,
      value3: 'youtube_public_release',
    },
  },
];
